    let x3: f32 = (-x2).exp();
    let x4: f32 = x3 - 1.0_f32;
    let x5: f32 = t / s;
    let x6: f32 = x4 * x5 + 1.0_f32;
    let x7: f32 = x6.powf(-w[20]);
    let x8: f32 = 1.0_f32 - x7;
    let x9: f32 = d.powf(-w[12]) * (w[14] * x8).exp();
    let x10: f32 = x9 * (x1 - 1.0_f32);
    let x11: f32 = w[11] * x10;
