    ds_dw[12] = -x11 * d.ln();
    ds_dw[13] = x12 * x0.ln();
    ds_dw[14] = x11 * x8;
    ds_dw[20] = -x14 * (-x13 * x2 * x3 * x5 - x6.ln());
