/// Short-term stability (unclamped sinc) and its gradients.
/// Returns (S_new, sinc, dS/dS_prev, dS/dw[0..21])
fn stability_short_term_grad(w: &[f32; 21], s: f32, r: f32) -> (f32, f32, f32, [f32; 21]) {
    let x0: f32 = s.powf(-w[19]);
    let x1: f32 = r + w[18] - 3.0_f32;
    let x2: f32 = (w[17] * x1).exp();
    let x3: f32 = x0 * x2;
    let x4: f32 = s * x3;

    let s_new: f32 = x4;
    let sinc_val: f32 = x3;
    let ds_ds: f32 = -w[19] * x3 + x0 * x2;
    let mut ds_dw = [0.0_f32; 21];
    ds_dw[17] = x1 * x4;
    ds_dw[18] = w[17] * x4;
    ds_dw[19] = -x4 * s.ln();
    (s_new, sinc_val, ds_ds, ds_dw)
}

